import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { createChanson, getChanson, updateChanson } from '../api/chansonService';

export default function ChansonForm(){
  const { id } = useParams();
  const navigate = useNavigate();
  const [model, setModel] = useState({ titre:'', duree:'' });
  const [loading, setLoading] = useState(false);

  useEffect(()=>{ if(id){ setLoading(true); getChanson(id).then(r=>setModel(r.data||{})).finally(()=>setLoading(false)); } },[id]);

  const submit = (e) => { e.preventDefault(); setLoading(true); const op = id ? updateChanson(id, model) : createChanson(model); op.then(()=>navigate('/chansons')).finally(()=>setLoading(false)); };

  return (
    <div>
      <h1>{id ? 'Modifier' : 'Créer'} Chanson</h1>
      <form onSubmit={submit}>
        <div>
          <label>Titre</label><br />
          <input value={model.titre||''} onChange={e=>setModel({...model, titre:e.target.value})} />
        </div>
        <div style={{marginTop:8}}>
          <label>Durée</label><br />
          <input value={model.duree||''} onChange={e=>setModel({...model, duree:e.target.value})} />
        </div>
        <div style={{marginTop:12}}>
          <button type="submit" disabled={loading}>{loading ? 'En cours...' : 'Enregistrer'}</button>
        </div>
      </form>
    </div>
  );
}
